     return BinaryOperator::CreateDisjointOr(LHS, RHS);
+  // (V / C1) * C2 + (V % C1) -> V + (V / C1) * (C2 - C1)
+  {
+    Value *V, *Div;
+    const APInt *C1, *C2;
+    if (match(&I, m_c_Add(m_OneUse(m_Mul(m_Value(Div), m_APInt(C2))),
+                          m_OneUse(m_URem(m_Value(V), m_APInt(C1))))) &&
+        match(Div, m_UDiv(m_Specific(V), m_SpecificInt(*C1))) &&
+        !C1->isZero() && C2->uge(*C1)) {
+      APInt Diff = *C2 - *C1;
+      Value *MulDiff = Builder.CreateMul(Div, ConstantInt::get(Ty, Diff));
+      Value *Add = Builder.CreateAdd(V, MulDiff);
+      return replaceInstUsesWith(I, Add);
+    }
+  }
+  // (V / C1) << ShAmt + (V % C1) -> V + (V / C1) * ((1 << ShAmt) - C1)
+  {
+    Value *V, *Div;
+    const APInt *C1, *ShAmt;
+    if (match(&I, m_c_Add(m_OneUse(m_Shl(m_Value(Div), m_APInt(ShAmt))),
+                          m_OneUse(m_URem(m_Value(V), m_APInt(C1))))) &&
+        match(Div, m_UDiv(m_Specific(V), m_SpecificInt(*C1))) &&
+        !C1->isZero() && ShAmt->ult(ShAmt->getBitWidth())) {
+      APInt C2 = APInt::getOneBitSet(C1->getBitWidth(), ShAmt->getZExtValue());
+      if (C2.uge(*C1)) {
+        APInt Diff = C2 - *C1;
+        Value *MulDiff = Builder.CreateMul(Div, ConstantInt::get(Ty, Diff));
+        Value *Add = Builder.CreateAdd(V, MulDiff);
+        return replaceInstUsesWith(I, Add);
+      }
+    }
+  }

   if (Instruction *Ext = narrowMathIfNoOverflow(I))
     return Ext;
